INSERT INTO categories (id, name, icon, description, tags, count, color) VALUES
  ('souks', 'Old Souks', 'fas fa-store-alt', 'Traditional markets dating back centuries', '["market","shopping","traditional","historic"]', 8, '#8B4513'),
  ('historical', 'Historical Sites', 'fas fa-landmark', 'Ancient castles, citadels and historical monuments', '["castle","fortress","ancient","heritage"]', 10, '#B8860B'),
  ('mosques', 'Mosques & Religious', 'fas fa-mosque', 'Beautiful mosques and religious architecture', '["religious","islamic","architecture","prayer"]', 8, '#228B22'),
  ('food', 'Food & Restaurants', 'fas fa-utensils', 'Traditional Lebanese cuisine and local eateries', '["food","restaurant","lebanese","cuisine"]', 10, '#DC143C'),
  ('cultural', 'Cultural Centers', 'fas fa-theater-masks', 'Museums, art galleries and cultural venues', '["museum","art","culture","gallery"]', 6, '#4B0082'),
  ('architecture', 'Architecture', 'fas fa-archway', 'Mamluk and Ottoman era architectural marvels', '["architecture","mamluk","ottoman","design"]', 8, '#2F4F4F');
INSERT INTO places (id, name, description, location, latitude, longitude, images, category, category_id, duration, price, best_time, rating, review_count, tags) VALUES
  ('citadel_raymond', 'Citadel of Raymond de Saint-Gilles', 'One of the largest and most impressive Crusader castles in the Middle East, built in the 12th century by Raymond de Saint-Gilles. The citadel offers breathtaking panoramic views of Tripoli and the Mediterranean Sea.', 'Citadel Hill, Tripoli', 34.4358, 35.8442, '["https://www.molon.de/galleries/Lebanon/Tripoli/images01/01%20Citadel%20of%20Raymond%20de%20Saint-Gilles.jpg"]', 'Historical Sites', 'historical', '2-3 hours', '5', 'Early Morning (8-10 AM) or Late Afternoon (4-6 PM)', 4.9, 342, '["castle","crusader","fortress","viewpoint","panoramic","historic"]'),
  ('khan_khayyatin', 'Khan al-Khayyatin (Tailors'' Market)', 'The largest covered market in Tripoli, dating back to the 14th century. This magnificent Mamluk-era structure spans over 1,200 square meters and houses dozens of textile shops and tailors.', 'Old City, Tripoli', 34.4333, 35.8333, '["https://mounzerhamze.com/wp-content/uploads/2020/09/Khayatine-4.jpg"]', 'Old Souks', 'souks', '1-2 hours', '0', 'Morning to Afternoon (9 AM - 4 PM)', 4.8, 256, '["market","textiles","historic","shopping","mamluk","crafts"]'),
  ('great_mosque_tripoli', 'Great Mosque of Tripoli (Jami'' al-Kabir)', 'Originally built as the Cathedral of St. Mary of the Tower by the Crusaders in the 12th century, converted to a mosque after the Mamluk conquest in 1289. Unique blend of Crusader and Islamic architecture.', 'Old City Center', 34.4344, 35.8361, '["https://c8.alamy.com/compfr/c8r7ny/cour-de-la-grande-mosquee-vieille-ville-tripoli-dans-le-nord-du-liban-c8r7ny.jpg"]', 'Mosques & Religious', 'mosques', '45 mins - 1 hour', '0', 'Morning (9-11 AM) or Between Prayer Times', 4.8, 198, '["mosque","crusader","converted","architecture","gothic","mamluk"]'),
  ('khan_saboun', 'Khan al-Saboun (Soap Khan)', 'Famous for traditional Tripoli olive oil soap production, dating back to the 17th century. Watch master soap makers demonstrate the ancient craft. Purchase authentic Tripoli soap in various shapes and scents.', 'Old City, near Clock Tower', 34.4336, 35.8344, '["https://luxortravel.net/storage/707/khan-al-saboun-tripoli.jpg"]', 'Old Souks', 'souks', '45 mins - 1 hour', '0', 'All Day (9 AM - 6 PM)', 4.7, 189, '["soap","traditional","crafts","shopping","olive oil","artisan"]'),
  ('taynal_mosque', 'Taynal Mosque', 'One of Tripoli''s most beautiful Mamluk mosques, built in 1336. Features stunning black and white striped stonework (ablaq), a magnificent minaret, and an elegant courtyard with a central fountain.', 'Old City Center', 34.4342, 35.8356, '["https://c8.alamy.com/comp/2JGW7BC/taynal-mosque-north-governorate-tripoli-lebanon-2JGW7BC.jpg"]', 'Mosques & Religious', 'mosques', '30-45 mins', '0', 'Between Prayer Times (10 AM - 12 PM or 2-4 PM)', 4.7, 167, '["mosque","mamluk","architecture","ablaq","minaret","peaceful"]'),
  ('hallab_sweets', 'Abdul Rahman Hallab & Sons', 'Tripoli''s most famous sweet shop, established in 1881. Renowned for baklava, knefeh, and maamoul. The shop''s beautiful Ottoman-era building features traditional architecture.', 'Azmi Street, City Center', 34.4367, 35.8378, '["https://th.bing.com/th/id/R.332ee0b3b534217c38bc47c08c343c83?rik=9%2f9eGIWwSfPtZQ&riu=http%3a%2f%2ftravelingwiththyme.com%2fwp-content%2fuploads%2f2018%2f02%2fHallab-Tripoli-Breakfast-Knefe-Lebanese-Sweets-5.jpg"]', 'Food & Restaurants', 'food', '30 mins', '10', 'All Day (8 AM - 10 PM)', 4.9, 567, '["sweets","baklava","traditional","famous","historic","confectionery"]'),
  ('clock_tower', 'Tripoli Clock Tower (Al-Sa''at Square)', 'Iconic Ottoman-era clock tower built in 1901 to commemorate Sultan Abdul Hamid II''s reign. Standing 30 meters tall, the heart of Tripoli''s old city. The square is always bustling with activity.', 'Al-Sa''at Square, City Center', 34.4361, 35.8383, '["https://c8.alamy.com/comp/CN0CPP/clock-tower-in-tripoli-CN0CPP.jpg"]', 'Historical Sites', 'historical', '20-30 mins', '0', 'All Day, Best at Sunset', 4.6, 312, '["landmark","ottoman","square","historic","iconic","meeting point"]'),
  ('madrasa_qartawiyya', 'Madrasa al-Qartawiyya', 'Stunning Mamluk-era Islamic school built in 1326. Features a beautiful courtyard with central fountain, intricate geometric patterns, elegant arches, and a magnificent portal with calligraphy.', 'Old City Center', 34.4339, 35.8353, '["https://c8.alamy.com/comp/ATD4YK/qartawiyya-madrasa-tripoli-lebanon-ATD4YK.jpg"]', 'Architecture', 'architecture', '45 mins - 1 hour', '0', 'Morning (9 AM - 12 PM)', 4.7, 145, '["madrasa","mamluk","geometric","courtyard","architecture","islamic school"]'),
  ('hammam_jadid', 'Hammam al-Jadid (New Hammam)', 'Unique dining in a restored 17th-century Ottoman hammam. Preserves original domed architecture, marble floors, and traditional bathhouse features while serving authentic Lebanese cuisine.', 'Old City Center', 34.4345, 35.8358, '["https://c8.alamy.com/comp/R5CPEG/lebanon-tripoli-old-town-el-jadid-hamam-bath-R5CPEG.jpg"]', 'Food & Restaurants', 'food', '1.5-2 hours', '25', 'Lunch (12-3 PM) or Dinner (7-10 PM)', 4.8, 124, '["restaurant","lebanese","traditional","historic","hammam","mezza"]'),
  ('gold_souk', 'Gold Souk (Souk al-Dhahab)', 'Vibrant market specializing in gold and jewelry with intricate designs and traditional Lebanese craftsmanship. Watch skilled goldsmiths at work. Bargaining is expected.', 'Old City, near Citadel', 34.4348, 35.8367, '["https://c8.alamy.com/comp/A3A73H/the-gold-souk-in-tripoli-libya-A3A73H.jpg"]', 'Old Souks', 'souks', '1-2 hours', '0', 'Afternoon (2-6 PM)', 4.5, 134, '["gold","jewelry","shopping","crafts","traditional","bargaining"]'),
  ('burtasiyat_mosque', 'Burtasiyat Mosque', 'Beautiful Mamluk mosque built in 1310, known for its elegant octagonal minaret and peaceful courtyard. Features traditional Mamluk architecture with black and white striped stonework.', 'Old City, near Port', 34.4328, 35.8322, '["https://thumbs.dreamstime.com/z/al-bertasi-mosque-tripoli-der-libanon-138151158.jpg"]', 'Mosques & Religious', 'mosques', '30 mins', '0', 'Between Prayer Times', 4.7, 98, '["mosque","mamluk","minaret","peaceful","port","octagonal"]'),
  ('spice_market', 'Spice Market (Souk al-Bahar)', 'Colorful and aromatic market filled with exotic spices, herbs, dried fruits, nuts, and traditional Middle Eastern ingredients. Perfect for za''atar, sumac, and regional specialties.', 'Old City, near Clock Tower', 34.4356, 35.8378, '["https://mybayutcdn.bayut.com/mybayut/wp-content/uploads/Spice-Souk-in-Dubai1-768x480.jpg"]', 'Old Souks', 'souks', '45 mins', '0', 'Morning (9 AM - 1 PM)', 4.7, 156, '["spices","herbs","food","aromatic","traditional","zaatar"]'),
  ('mina_fish_market', 'Al-Mina Fish Market', 'Bustling fish market and restaurant by the port. Select fresh seafood caught daily from the Mediterranean. Have it grilled with traditional Lebanese sides.', 'Al-Mina Port', 34.4311, 35.8289, '["https://lebanonuntravelled.com/wp/wp-content/uploads/2017/08/mina-2.jpg"]', 'Food & Restaurants', 'food', '1.5-2 hours', '30', 'Lunch (12-3 PM) or Early Dinner (6-8 PM)', 4.7, 223, '["seafood","fresh","port","grilled","market","mediterranean"]'),
  ('muallaq_mosque', 'Al-Muallaq Mosque (Hanging Mosque)', 'Unique mosque built in the 16th century, known as the Hanging Mosque because it was constructed over shops and market stalls. Features beautiful Mamluk architecture and intricate decorations.', 'Old City Center', 34.4341, 35.8351, '["https://i0.wp.com/tripoli-lebanon.com/wp/wp-content/uploads/2021/07/11.jpg?w=890&ssl=1"]', 'Mosques & Religious', 'mosques', '30-45 mins', '0', 'Between Prayer Times', 4.8, 167, '["mosque","mamluk","unique","architecture","hanging","innovative"]'),
  ('khan_askar', 'Khan al-Askar (Soldiers'' Khan)', 'Historic covered market from the Mamluk period. Today houses shops selling traditional crafts, textiles, and souvenirs. Beautiful vaulted ceilings and stone arches.', 'Old City Center', 34.4335, 35.8347, '["https://mounzerhamze.com/wp-content/uploads/2020/09/khan-alaskar-1.jpg"]', 'Old Souks', 'souks', '1 hour', '0', 'Morning (9 AM - 1 PM)', 4.6, 112, '["market","historic","mamluk","crafts","authentic","local"]'),
  ('attar_mosque', 'Al-Attar Mosque', 'Historic Mamluk mosque built in 1330, known for stunning geometric patterns and traditional Islamic architecture. Beautiful black and white striped stonework and impressive minaret.', 'Old City Center', 34.4343, 35.8355, '["https://c8.alamy.com/comp/C8R7BW/al-attar-mosque-from-the-14th-century-souk-tripoli-northern-lebanon-C8R7BW.jpg"]', 'Mosques & Religious', 'mosques', '30 mins', '0', 'Between Prayer Times', 4.6, 89, '["mosque","mamluk","geometric","islamic","calligraphy","peaceful"]'),
  ('furn_samak', 'Furn al-Samak (Fish Bakery)', 'Local favorite famous for fresh fish sandwiches and traditional manakish. Unassuming street food spot serving locals for decades. Simple, authentic flavors.', 'Old City, near Souks', 34.4347, 35.8362, '["https://fastly.4sqi.net/img/general/600x600/32512262_yh_uoVI26en0VXoC9NjXwTPED6q3mPwLmGTlvblBsso.jpg"]', 'Food & Restaurants', 'food', '30-45 mins', '8', 'Lunch (11 AM - 2 PM)', 4.8, 289, '["street food","fish","manakish","local","bakery","authentic"]'),
  ('mamluk_mansions', 'Mamluk Mansions District', 'Collection of well-preserved Mamluk-era mansions showcasing opulent lifestyle. Intricate stonework, beautiful courtyards with fountains, elegant arches.', 'Old City Residential Area', 34.4325, 35.8339, '["https://mediorientedintorni.com/wp-content/uploads/2020/06/photo6021345137843614465-1024x683.jpg"]', 'Architecture', 'architecture', '1-1.5 hours', '0', 'Morning Light (9-11 AM) for Best Photography', 4.6, 78, '["mamluk","mansions","stonework","historic","residential","elite"]'),
  ('tripoli_museum', 'Tripoli Museum of History', 'Comprehensive museum showcasing Tripoli''s history from Phoenician times through Crusader, Mamluk, Ottoman, and modern eras. Artifacts, pottery, coins, weapons, manuscripts.', 'Azmi Street', 34.4372, 35.8391, '["https://onlybyland.com/wp-content/uploads/2019/07/tripoli10.jpg"]', 'Cultural Centers', 'cultural', '1.5-2 hours', '3', 'Morning or Afternoon (9 AM - 4 PM)', 4.5, 145, '["museum","history","artifacts","educational","phoenician","ottoman"]'),
  ('ottoman_hammams', 'Ottoman Hammams (Public Baths)', 'Historic 17th-century public baths with beautiful domed architecture. Large domed chambers, marble floors, intricate tile work. Some converted into cultural spaces or restaurants.', 'Old City Center', 34.4346, 35.8359, '["https://th.bing.com/th/id/R.b9bd7d8f6acde278ad301ebaad582a37"]', 'Architecture', 'architecture', '45 mins - 1 hour', '0', 'Morning (9 AM - 12 PM)', 4.5, 98, '["ottoman","hammam","domed","historic","architecture","public baths"]'),
  ('azhar_cultural', 'Al-Azhar Cultural Center', 'Modern cultural center hosting art exhibitions, concerts, theater, and cultural events. Contemporary architecture and state-of-the-art facilities.', 'City Center', 34.4375, 35.8389, '["https://i.pinimg.com/736x/e3/d1/be/e3d1beddef73a212d00b235950a1f674.jpg"]', 'Cultural Centers', 'cultural', '1-2 hours', '5', 'Afternoon or Evening (Check Event Schedule)', 4.4, 67, '["art","exhibitions","events","modern","cultural","theater"]'),
  ('khayyam_restaurant', 'Al-Khayyam Restaurant', 'Traditional Lebanese restaurant serving authentic mezza, grilled meats, and regional specialties. Extensive selection of hot and cold mezza in a historic setting.', 'Old City Center', 34.4349, 35.8361, '["https://images.happycow.net/venues/1024/34/57/hcmp345753_2078001.jpeg"]', 'Food & Restaurants', 'food', '1.5-2 hours', '20', 'Dinner (7-10 PM)', 4.6, 189, '["lebanese","mezza","traditional","grilled","authentic","historic"]'),
  ('tripoli_art_gallery', 'Tripoli Art Gallery', 'Contemporary art gallery featuring works by local and regional artists. Rotating exhibitions of paintings, sculptures, installations, and mixed media.', 'Azmi Street', 34.4378, 35.8395, '["https://i.etsystatic.com/23852101/r/il/a25d14/4589999487/il_1080xN.4589999487_910a.jpg"]', 'Cultural Centers', 'cultural', '1 hour', '2', 'Afternoon (2-6 PM)', 4.6, 89, '["gallery","art","contemporary","local artists","exhibitions","modern"]'),
  ('khan_misriyye', 'Khan al-Misriyye (Egyptian Khan)', 'Historic khan built in the 14th century, originally used by Egyptian merchants. Beautiful Mamluk architecture with central courtyard and arched passageways.', 'Old City Center', 34.4337, 35.8349, '["https://i0.wp.com/tripoli-lebanon.com/wp/wp-content/uploads/2021/06/khan-misriin.jpg?w=886&ssl=1"]', 'Old Souks', 'souks', '45 mins - 1 hour', '0', 'Morning (9 AM - 1 PM)', 4.5, 78, '["market","historic","mamluk","crafts","egyptian","merchants"]'),
  ('madrasa_nuriyya', 'Madrasa al-Nuriyya', 'Beautiful Mamluk-era Islamic school built in 1333. Elegant courtyard, beautiful portal with calligraphy, peaceful atmosphere.', 'Old City Center', 34.4340, 35.8352, '["https://c8.alamy.com/comp/ATD89X/nuriyya-madrasa-tripoli-lebanon-ATD89X.jpg"]', 'Architecture', 'architecture', '45 mins', '0', 'Morning (9 AM - 12 PM)', 4.6, 67, '["madrasa","mamluk","architecture","islamic school","courtyard","peaceful"]'),
  ('abu_ali_river', 'Abu Ali River Promenade', 'Scenic promenade along the Abu Ali River. Walking paths, cafes, green spaces. Beautiful views of river, bridges, and surrounding architecture.', 'Along Abu Ali River', 34.4389, 35.8400, '["https://thumbs.dreamstime.com/z/medieval-citadel-next-to-river-abou-ali-tripoli-lebanon-162839614.jpg"]', 'Historical Sites', 'historical', '1 hour', '0', 'Evening (5-8 PM) or Early Morning', 4.4, 112, '["river","promenade","scenic","peaceful","walking","cafes"]'),
  ('cafe_nostalgie', 'Cafe Younes', 'Charming traditional café serving authentic Lebanese coffee, tea, and light snacks. Vintage furniture, old photographs. Locals gather to play backgammon and socialize.', 'Old City Center', 34.4351, 35.8365, '["https://www.lebanontraveler.com/wp-content/uploads/2023/04/Cafe-Younes-3-FINAL-1024x538.jpg"]', 'Food & Restaurants', 'food', '45 mins - 1 hour', '5', 'All Day, Best in Afternoon', 4.5, 198, '["cafe","coffee","traditional","local","backgammon","nostalgic"]'),
  ('khan_shuna', 'Khan al-Shuna', 'Historic khan from the Mamluk period. Central courtyard surrounded by two-story arcades. Shops selling traditional products, crafts, and local goods.', 'Old City Center', 34.4338, 35.8350, '["https://i.pinimg.com/originals/38/36/99/38369921bb692bb5314fac5a39ede69c.jpg"]', 'Old Souks', 'souks', '45 mins - 1 hour', '0', 'Morning (9 AM - 1 PM)', 4.5, 89, '["market","historic","mamluk","architecture","courtyard","traditional"]'),
  ('sidi_abdul_wahid', 'Sidi Abdul Wahid Mosque', 'Historic mosque built in the 14th century, dedicated to a local saint. Traditional Mamluk architecture with beautiful minaret and peaceful interior.', 'Old City Center', 34.4334, 35.8345, '["https://i0.wp.com/tripoli-lebanon.com/wp/wp-content/uploads/2021/07/list3-09.jpg?resize=893%2C583&ssl=1"]', 'Mosques & Religious', 'mosques', '20-30 mins', '0', 'Between Prayer Times', 4.5, 56, '["mosque","mamluk","saint","spiritual","peaceful","historic"]'),
  ('tripoli_lighthouse', 'Tripoli Lighthouse', 'Historic Ottoman-era lighthouse at the port entrance. Has guided ships for over a century. Beautiful views of the Mediterranean, especially at sunset.', 'Al-Mina Port', 34.4300, 35.8250, '["https://safarimagazines.com/wp-content/uploads/2024/01/Tripoli-Lebanon.jpg"]', 'Historical Sites', 'historical', '30-45 mins', '0', 'Sunset (5-7 PM)', 4.4, 134, '["lighthouse","port","maritime","sunset","ottoman","historic"]'),
  ('bakery_rahal', 'Rahal Bakery', 'Traditional Lebanese bakery famous for fresh bread, manakish, and pastries. Traditional stone ovens and time-honored recipes. Watch bakers at work.', 'Old City, near Souks', 34.4346, 35.8363, '["https://image.shutterstock.com/z/stock-photo-tripoli-lebanon-october-bakery-stall-on-the-market-1248862540.jpg"]', 'Food & Restaurants', 'food', '20-30 mins', '3', 'Morning (7-11 AM) for Fresh Bread', 4.6, 167, '["bakery","bread","manakish","traditional","fresh","local"]'),
  ('khan_aziz', 'Khan al-Aziz', 'Smaller charming khan with traditional architecture. Shops selling local crafts, textiles, traditional products. More intimate, less crowded atmosphere.', 'Old City Center', 34.4336, 35.8348, '["https://blogger.googleusercontent.com/img/b/R29vZ2xl/AVvXsEhjOkQSMpKkAzkF4J5cqMsYIN5ZTfiv5S89B42iDW5fgf6iDidC0hVl95paXCoFntlOTELU2uktyC1e2xI2nHNS06W5Cc5kNH37hO6Ie2jf0QrSOSwiqrCQmFHNGy-jA4YoAwFLwOFPoCV0/w1200-h630-p-k-no-nu/Lebanon53.jpg"]', 'Old Souks', 'souks', '30-45 mins', '0', 'Morning (9 AM - 1 PM)', 4.4, 78, '["market","historic","crafts","intimate","traditional","local"]'),
  ('madrasa_tawriziyya', 'Madrasa al-Tawriziyya', 'Beautiful Mamluk-era Islamic school built in 1326. Elegant courtyard, portal with geometric patterns. Sophisticated Mamluk architectural style.', 'Old City Center', 34.4341, 35.8354, '["https://c8.alamy.com/comp/ATDEGN/mashad-madrasa-tripoli-lebanon-ATDEGN.jpg"]', 'Architecture', 'architecture', '45 mins', '0', 'Morning (9 AM - 12 PM)', 4.6, 67, '["madrasa","mamluk","architecture","islamic school","geometric","peaceful"]'),
  ('seafood_restaurant_port', 'Port Seafood Restaurant', 'Popular seafood restaurant by the port. Fresh Mediterranean fish and seafood. Grilled catch of the day with traditional Lebanese sides. Casual, authentic atmosphere.', 'Al-Mina Port', 34.4315, 35.8295, '["https://ibnbattutatravel.com/wp-content/uploads/listing-images/ibnbattuta-DJAxPDc-JUnV6-t8v.jpg"]', 'Food & Restaurants', 'food', '1.5 hours', '28', 'Lunch (12-3 PM) or Dinner (6-9 PM)', 4.6, 145, '["seafood","mediterranean","port","grilled","fresh","casual"]'),
  ('cultural_heritage_center', 'Tripoli Cultural Heritage Center', 'Center preserving Tripoli''s cultural heritage through exhibitions and workshops. Traditional crafts, local customs. Workshops on soap making, weaving, metalwork.', 'City Center', 34.4376, 35.8393, '["https://whc.unesco.org/uploads/thumbs/news_2516-890-520-20230125154848.jpg"]', 'Cultural Centers', 'cultural', '1-1.5 hours', '4', 'Afternoon (2-5 PM)', 4.5, 89, '["cultural","heritage","crafts","workshops","traditional","educational"]'),
  ('ottoman_house', 'Restored Ottoman House', 'Beautifully restored 19th-century Ottoman house as museum and cultural space. Central courtyard, elegant rooms, traditional furnishings.', 'Old City Residential Area', 34.4327, 35.8341, '["https://idsb.tmgrup.com.tr/ly/uploads/images/2021/09/29/148524.jpg"]', 'Architecture', 'architecture', '45 mins - 1 hour', '2', 'Morning (9 AM - 12 PM)', 4.5, 78, '["ottoman","house","restored","museum","residential","traditional"]'),
  ('sweets_shop_rahal', 'Rahal Sweets Shop', 'Traditional sweet shop with fresh baklava, knefeh, maamoul. Made daily using time-honored recipes. Beautifully arranged display cases.', 'City Center', 34.4370, 35.8385, '["https://i0.wp.com/travelingwiththyme.com/wp-content/uploads/2018/02/Abdul-Rahman-Hallab-Lebanese-Oriental-Sweets-4.jpg?resize=768%2C512&ssl=1"]', 'Food & Restaurants', 'food', '20-30 mins', '8', 'All Day (9 AM - 9 PM)', 4.7, 198, '["sweets","baklava","pastries","traditional","desserts","local"]'),
  ('khan_franji', 'Khan al-Franji (Frankish Khan)', 'Historic khan from the Crusader period, later used by European merchants. Mix of Crusader and Mamluk architectural styles. Testament to Tripoli''s role as trading hub.', 'Old City Center', 34.4339, 35.8351, '["https://www.rjtravelagency.com/wp-content/uploads/2023/04/Khan-Al-Franj.jpg"]', 'Old Souks', 'souks', '45 mins - 1 hour', '0', 'Morning (9 AM - 1 PM)', 4.5, 67, '["market","historic","crusader","frankish","trading","architecture"]'),
  ('mosque_umari', 'Al-Umari Mosque', 'Historic mosque built in the 14th century. Traditional Mamluk design with elegant proportions, intricate decorations. Impressive minaret with detailed stonework.', 'Old City Center', 34.4344, 35.8357, '["https://cdn.britannica.com/24/143424-050-7F100795/Great-Mosque-Tripoli-Leb.jpg"]', 'Mosques & Religious', 'mosques', '30 mins', '0', 'Between Prayer Times', 4.5, 56, '["mosque","mamluk","historic","spiritual","peaceful","architecture"]'),
  ('traditional_cafe_old_city', 'Traditional Café in Old City', 'Authentic traditional café. Strong Turkish coffee, sweet tea, light snacks. Locals gather to socialize and play backgammon. Genuine taste of local café culture.', 'Old City Center', 34.4352, 35.8366, '["https://c8.alamy.com/compfr/bxcrty/tripoli-liban-les-hommes-dans-un-cafe-bxcrty.jpg"]', 'Food & Restaurants', 'food', '45 mins - 1 hour', '4', 'Afternoon (2-6 PM)', 4.4, 123, '["cafe","coffee","traditional","local","backgammon","authentic"]'),
  ('mamluk_fountain', 'Mamluk Public Fountain', 'Beautiful Mamluk-era public fountain. Intricate stonework, geometric patterns, traditional Islamic decorations. Reminder of sophisticated Mamluk public works.', 'Old City Center', 34.4347, 35.8360, '["https://th.bing.com/th/id/R.1b6079df1f75e3e7c6967cb6e40b0c3f"]', 'Architecture', 'architecture', '15-20 mins', '0', 'All Day', 4.4, 45, '["fountain","mamluk","architecture","public works","geometric","historic"]'),
  ('lebanese_restaurant_azmi', 'Traditional Lebanese Restaurant', 'Family-owned restaurant serving authentic Lebanese cuisine. Extensive mezza, grilled meats. Warm, traditional setting with friendly service.', 'Azmi Street', 34.4373, 35.8390, '["https://cdn.nogarlicnoonions.com/images/thumbs/image.php?width=700&height=400&cropratio=700:400&image=/images/articles/2016-12/shater-hassan-tripoli-lebanese-restaurant182016-12-24-11-24-18.jpg"]', 'Food & Restaurants', 'food', '1.5-2 hours', '22', 'Lunch (12-3 PM) or Dinner (7-10 PM)', 4.6, 167, '["lebanese","mezza","traditional","family-owned","authentic","hospitality"]'),
  ('artisan_workshop', 'Traditional Artisan Workshop', 'Working artisan workshop. Watch traditional crafts: metalwork, woodwork, textile weaving. Preserves techniques passed down through generations. Purchase handmade products.', 'Old City Center', 34.4342, 35.8359, '["https://www.shutterstock.com/image-photo/tripoli-lebanon-july-27-2022-600nw-2535286823.jpg"]', 'Cultural Centers', 'cultural', '1 hour', '0', 'Morning (9 AM - 1 PM)', 4.5, 78, '["artisan","crafts","workshop","traditional","handmade","cultural"]');
INSERT INTO interests (id, name, icon, description, color, count, popularity, tags) VALUES
  ('culture', 'Culture & Heritage', 'landmark', 'Historic sites, traditions and local culture', '#8B4513', 0, 10, '[]'),
